import{_ as e,c as a,o as t,a as r}from"./app.6ebd288d.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[{"level":2,"title":"透视相机(PerspectiveCamera)","slug":"透视相机-perspectivecamera","link":"#透视相机-perspectivecamera","children":[]},{"level":2,"title":"材质","slug":"材质","link":"#材质","children":[]},{"level":2,"title":"光源","slug":"光源","link":"#光源","children":[]}],"relativePath":"4.库/threejs/api.md","lastUpdated":1678376011000}'),c={name:"4.库/threejs/api.md"},o=r('<h2 id="透视相机-perspectivecamera" tabindex="-1"><a href="https://threejs.org/docs/#api/zh/cameras/PerspectiveCamera" target="_blank" rel="noreferrer">透视相机(<code>PerspectiveCamera</code>)</a> <a class="header-anchor" href="#透视相机-perspectivecamera" aria-hidden="true">#</a></h2><blockquote><p>参考资料：</p><p><a href="https://juejin.cn/post/7055179266773745672" target="_blank" rel="noreferrer">https://juejin.cn/post/7055179266773745672</a></p></blockquote><p>在<code>three.js</code>中，<code>摄像机</code>的作用就是不断的拍摄我们创建好的场景，然后通过<code>渲染器</code>渲染到屏幕中。想通过不同的角度观看场景，就需要修改<code>摄像机</code>的位置来拍摄场景。本文详细介绍的是<code>透视相机（PerspectiveCamera）</code> 它是用来模拟人眼所看到的景象，它也是3D场景的渲染中使用得最普遍的投影模式。</p><ul><li>根据视锥的范围给<code>渲染器</code>提供需要渲染的场景范围。</li><li>实例化<code>new THREE.PerspectiveCamera()</code> 接受4个参数来确认视锥的范围。只要在视锥范围内的场景才会渲染。</li></ul><ol><li><code>fov</code> 摄像机视锥体垂直视野角度。</li><li><code>aspect</code> 摄像机视锥体长宽比。</li><li><code>near</code> 摄像机视锥体近端面。</li><li><code>far</code> 摄像机视锥体远端面。</li></ol><h2 id="材质" tabindex="-1">材质 <a class="header-anchor" href="#材质" aria-hidden="true">#</a></h2><h2 id="光源" tabindex="-1">光源 <a class="header-anchor" href="#光源" aria-hidden="true">#</a></h2><blockquote><p><a href="https://threejs.org/docs/#api/zh/lights/AmbientLight" target="_blank" rel="noreferrer">https://threejs.org/docs/#api/zh/lights/AmbientLight</a></p></blockquote>',8),i=[o];function s(d,l,h,n,p,_){return t(),a("div",null,i)}const f=e(c,[["render",s]]);export{u as __pageData,f as default};
